Write the final color to gl_FragColor. Reference shader for a glow effect:

precision mediump float;
uniform sampler2D u_texture;
uniform float u_time;
uniform vec2 u_resolution;
varying vec2 v_uv;

void main() {
  vec3 base = texture2D(u_texture, v_uv).rgb;
  vec2 px = 1.0 / u_resolution;
  vec3 bloom = vec3(0.0);
  float wsum = 0.0;
  for (float dx = -3.0; dx <= 3.0; dx += 1.0) {
    for (float dy = -3.0; dy <= 3.0; dy += 1.0) {
      vec3 s = texture2D(u_texture, v_uv + vec2(dx, dy) * px * 2.0).rgb;
      float lum = dot(s, vec3(0.2126, 0.7152, 0.0722));
      float w = smoothstep(0.55, 0.95, lum);
      bloom += s * w;
      wsum += w;
    }
  }
  bloom /= max(wsum, 1.0);
  float pulse = 0.7 + 0.3 * sin(u_time * 2.5);
  gl_FragColor = vec4(clamp(base + bloom * 1.2 * pulse, 0.0, 1.0), 1.0);
}

